previewCss:
.darma-loader-darma-custom-645__earth { color: var(--loader-color, #2563eb); --loader-secondary-color: var(--loader-secondary-color, #22c55e); --loader-bg: var(--loader-bg, #0f172a); }
.darma-loader-darma-custom-645__earth-loader {
  --watercolor: #3344c1;
  --landcolor: #7cc133;
  width: 7.5em;
  height: 7.5em;
  background-color: var(--watercolor);
  position: relative;
  overflow: hidden;
  border-radius: 50%;
  box-shadow:
    inset 0em 0.5em rgb(255, 255, 255, 0.25),
    inset 0em -0.5em rgb(0, 0, 0, 0.25);
  border: solid 0.15em white;
  animation: darma-loader-darma-custom-645-startround 1s;
  animation-iteration-count: 1;
}

.darma-loader-darma-custom-645__earth p {
  color: white;
  display: flex;
  justify-content: center;
  align-items: center;
  padding-top: 0.25em;
  font-size: 1.25em;
  font-family: "Gill Sans", "Gill Sans MT", Calibri, "Trebuchet MS", sans-serif;
}

.darma-loader-darma-custom-645__earth-loader svg:nth-child(1) {
  position: absolute;
  bottom: -2em;
  width: 7em;
  height: auto;
  animation: darma-loader-darma-custom-645-round1 5s infinite linear 0.75s;
}

.darma-loader-darma-custom-645__earth-loader svg:nth-child(2) {
  position: absolute;
  top: -3em;
  width: 7em;
  height: auto;
  animation: darma-loader-darma-custom-645-round1 5s infinite linear;
}
.darma-loader-darma-custom-645__earth-loader svg:nth-child(3) {
  position: absolute;
  top: -2.5em;
  width: 7em;
  height: auto;
  animation: darma-loader-darma-custom-645-round2 5s infinite linear;
}
.darma-loader-darma-custom-645__earth-loader svg:nth-child(4) {
  position: absolute;
  bottom: -2.2em;
  width: 7em;
  height: auto;
  animation: darma-loader-darma-custom-645-round2 5s infinite linear 0.75s;
}

@keyframes darma-loader-darma-custom-645-startround {
  0% {
    filter: brightness(500%);
    box-shadow: none;
  }
  75% {
    filter: brightness(500%);
    box-shadow: none;
  }
  100% {
    filter: brightness(100%);
    box-shadow:
      inset 0em 0.5em rgb(255, 255, 255, 0.25),
      inset 0em -0.5em rgb(0, 0, 0, 0.25);
  }
}

@keyframes darma-loader-darma-custom-645-round1 {
  0% {
    left: -2em;
    opacity: 1;
    transform: skewX(0deg) rotate(0deg);
  }
  30% {
    left: -6em;
    opacity: 1;
    transform: skewX(-25deg) rotate(25deg);
  }
  31% {
    left: -6em;
    opacity: 0;
    transform: skewX(-25deg) rotate(25deg);
  }
  35% {
    left: 7em;
    opacity: 0;
    transform: skewX(25deg) rotate(-25deg);
  }
  45% {
    left: 7em;
    opacity: 1;
    transform: skewX(25deg) rotate(-25deg);
  }
  100% {
    left: -2em;
    opacity: 1;
    transform: skewX(0deg) rotate(0deg);
  }
}

@keyframes darma-loader-darma-custom-645-round2 {
  0% {
    left: 5em;
    opacity: 1;
    transform: skewX(0deg) rotate(0deg);
  }
  75% {
    left: -7em;
    opacity: 1;
    transform: skewX(-25deg) rotate(25deg);
  }
  76% {
    left: -7em;
    opacity: 0;
    transform: skewX(-25deg) rotate(25deg);
  }
  77% {
    left: 8em;
    opacity: 0;
    transform: skewX(25deg) rotate(-25deg);
  }
  80% {
    left: 8em;
    opacity: 1;
    transform: skewX(25deg) rotate(-25deg);
  }
  100% {
    left: 5em;
    opacity: 1;
    transform: skewX(0deg) rotate(0deg);
  }
}

